-- ============================================================
-- YUNO MADRID → YUNO APP AFFILIATE MIGRATION
-- Run in Yuno App Supabase SQL Editor
-- Step 1: Creates the Yuno Internal affiliate record
-- Step 2: Inserts 22 clubs as affiliate_venues
-- Step 3: Inserts upcoming events as affiliate_events
-- ============================================================

BEGIN;

-- --------------------------------------------------------
-- STEP 1: Create Yuno Internal affiliate (update the user_id!)
-- Replace 'YOUR-ADMIN-USER-UUID' with your actual admin user UUID
-- You can find it in Supabase Auth → Users
-- --------------------------------------------------------

INSERT INTO affiliates (id, user_id, name, type, city, commission_rate, tracking_prefix, is_active)
VALUES (
  'a0000000-0000-0000-0000-000000000001',
  'YOUR-ADMIN-USER-UUID',  -- << REMPLACE PAR TON UUID ADMIN
  'Yuno Madrid',
  'yuno_internal',
  'Madrid',
  0,
  'madrid',
  true
) ON CONFLICT (user_id) DO UPDATE SET
  name = EXCLUDED.name,
  type = EXCLUDED.type,
  city = EXCLUDED.city,
  tracking_prefix = EXCLUDED.tracking_prefix;

-- Also grant affiliate role (if not already granted)
INSERT INTO user_roles (user_id, role)
VALUES ('YOUR-ADMIN-USER-UUID', 'affiliate')
ON CONFLICT DO NOTHING;

